local function b64decode(data)
	local alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
	data = string.gsub(data, "[^" .. alphabet .. "=]", "")
	return (data:gsub(".", function(x)
		if x == "=" then
			return ""
		end

		local r, f = "", (alphabet:find(x, 1, true) or 1) - 1
		for i = 6, 1, -1 do
			r = r .. (f % 2 ^ i - f % 2 ^ (i - 1) > 0 and "1" or "0")
		end
		return r
	end):gsub("%d%d%d?%d?%d?%d?%d?%d?", function(x)
		if #x ~= 8 then
			return ""
		end

		local c = 0
		for i = 1, 8 do
			c = c + (x:sub(i, i) == "1" and 2 ^ (8 - i) or 0)
		end
		return string.char(c)
	end))
end

local function getParent()
	local parent
	pcall(function()
		if typeof(gethui) == "function" then
			parent = gethui()
		end
	end)

	if parent then
		return parent
	end

	local player = Players.LocalPlayer
	local playerGui = player and player:FindFirstChildOfClass("PlayerGui")
	return playerGui or game:GetService("CoreGui")
end

local function canUseCustomAsset()
	return typeof(writefile) == "function" and typeof(getcustomasset) == "function"
end

local function ensureFolder(folder)
	if typeof(makefolder) == "function" and typeof(isfolder) == "function" then
		if not isfolder(folder) then
			pcall(makefolder, folder)
		end
	end
end

local function resolveGoogleImage()
	if SETTINGS.CustomImage ~= "" then
		return SETTINGS.CustomImage
	end

	if not canUseCustomAsset() then
		return ""
	end

	local folder = "GoogleIntroAssets"
	local path = folder .. "/google_g_clean_" .. GOOGLE_G_PNG_SHA .. ".png"

	ensureFolder(folder)

	local exists = false
	if typeof(isfile) == "function" then
		pcall(function()
			exists = isfile(path)
		end)
	end

	if not exists then
		local decoded = b64decode(GOOGLE_G_PNG_B64)
		local ok = pcall(function()
			writefile(path, decoded)
		end)
		if not ok then
			return ""
		end
	end

	local ok, asset = pcall(function()
		return getcustomasset(path)
	end)

	if ok and asset then
		return asset
	end

	return ""
end

local function easeOutCubic(x)
	x = math.clamp(x, 0, 1)
	return 1 - ((1 - x) ^ 3)
end

local function easeInOutCubic(x)
	x = math.clamp(x, 0, 1)
	if x < 0.5 then
		return 4 * x * x * x
	end
	return 1 - ((-2 * x + 2) ^ 3) / 2
end

local function easeOutBack(x)
	x = math.clamp(x, 0, 1)
	local c1 = 1.45
	local c3 = c1 + 1
	return 1 + c3 * ((x - 1) ^ 3) + c1 * ((x - 1) ^ 2)
end

local function range(t, a, b)
	return math.clamp((t - a) / (b - a), 0, 1)
end

