local startTime = os.clock()
local exiting = false
local fadeStart = 0
local fadeLength = 0.28
local connection

connection = RunService.RenderStepped:Connect(function()
	local elapsed = os.clock() - startTime

	if SETTINGS.Loop then
		local p = (elapsed % SETTINGS.Duration) / SETTINGS.Duration
		local eased = easeInOutCubic(p)
		spinRoot.Rotation = eased * 360 * SETTINGS.SpinTurns
		scale.Scale = 1 + math.sin(p * math.pi * 2) * 0.025
		return
	end

	if not exiting then
		local p = math.clamp(elapsed / SETTINGS.Duration, 0, 1)
		local intro = easeOutBack(range(elapsed, 0, 0.42))
		local spin = easeInOutCubic(p)
		local rotation = spin * 360 * SETTINGS.SpinTurns

		if SETTINGS.ReturnToOriginal and p >= 0.999 then
			rotation = 0
		end

		spinRoot.Rotation = rotation
		scale.Scale = 0.72 + (0.28 * intro)
		center.Position = UDim2.fromScale(0.5, 0.5 + ((1 - easeOutCubic(range(elapsed, 0, 0.48))) * 0.018))

		if p >= 1 then
			if SETTINGS.ReturnToOriginal then
				spinRoot.Rotation = 0
				center.Position = UDim2.fromScale(0.5, 0.5)
				scale.Scale = 1
			end

			if SETTINGS.FadeOut then
				exiting = true
				fadeStart = os.clock()
			else
				if connection then
					connection:Disconnect()
				end
			end
		end
	else
		local p = math.clamp((os.clock() - fadeStart) / fadeLength, 0, 1)
		local e = easeInOutCubic(p)

		background.BackgroundTransparency = math.min(1, (SETTINGS.BackgroundDim and 0.18 or 1) + e)
		center.Position = UDim2.fromScale(0.5, 0.5 - (0.012 * e))
		scale.Scale = 1 - (0.08 * e)

		for _, obj in ipairs(gui:GetDescendants()) do
			if obj:IsA("ImageLabel") then
				obj.ImageTransparency = math.max(obj.ImageTransparency, e)
			elseif obj:IsA("TextLabel") then
				obj.TextTransparency = math.max(obj.TextTransparency, e)
			elseif obj:IsA("Frame") and obj ~= background and obj ~= center and obj ~= spinRoot then
				obj.BackgroundTransparency = math.max(obj.BackgroundTransparency, e)
			elseif obj:IsA("UIStroke") then
				obj.Transparency = math.max(obj.Transparency, e)
			end
		end

		if p >= 1 then
			if connection then
				connection:Disconnect()
			end
			gui:Destroy()
		end
	end
end)
